/**
 * RADAR Status Page (Maps Monitoring)
 *
 * Checks the health status of Bing Maps and Google Maps.
 * 
 * Technical Implementation:
 * 1. Scraping: Attempts to fetch status page HTML via CORS proxies (AllOrigins, CORSProxy.io).
 *    It parses the HTML response text for known "Up" or "Down" keywords/classes.
 * 2. Fallback (Direct Ping): If scraping fails, it attempts to load a generic 1x1 or tile image 
 *    directly from the maps CDN. This is an effective way to verify connectivity even if CORS prevents reading the response data.
 */

import React, { useEffect, useState } from 'react';
import { BackArrowIcon, MapLocationIcon } from './icons';

interface RadarStatusPageProps {
  onBack: () => void;
}

type Status = 'healthy' | 'warning' | 'critical' | 'unreachable' | 'loading' | 'unknown';

const RadarStatusPage: React.FC<RadarStatusPageProps> = ({ onBack }) => {
  const [bingStatus, setBingStatus] = useState<Status>('loading');
  const [googleStatus, setGoogleStatus] = useState<Status>('loading');

  // Debug states to hold the raw response for verification
  const [bingDebug, setBingDebug] = useState<string>('');
  const [googleDebug, setGoogleDebug] = useState<string>('');

  useEffect(() => {
    // Helper to perform a direct functional test of the service
    // This bypasses CORS issues by attempting to load an image (opaque response)
    // If the image loads, the service is definitely UP.
    const testDirectConnection = (testImageUrl: string): Promise<boolean> => {
      return new Promise((resolve) => {
        const img = new Image();
        img.onload = () => resolve(true);
        img.onerror = () => resolve(false);
        // Add timestamp to prevent caching
        img.src = `${testImageUrl}&_t=${new Date().getTime()}`;
      });
    };

    const fetchWithFallback = async (targetUrl: string, proxies: string[]): Promise<string> => {
      let lastError;
      for (const proxyBase of proxies) {
        try {
          // Construct URL based on proxy type
          let fullUrl = '';
          if (proxyBase.includes('allorigins')) {
             fullUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(targetUrl)}`;
          } else if (proxyBase.includes('corsproxy.io')) {
             fullUrl = `${proxyBase}?${encodeURIComponent(targetUrl)}`;
          } else {
             fullUrl = `${proxyBase}${encodeURIComponent(targetUrl)}`;
          }

          const response = await fetch(fullUrl);
          if (!response.ok) throw new Error(`HTTP ${response.status} from ${proxyBase}`);

          let text = '';
          if (proxyBase.includes('allorigins')) {
             const json = await response.json();
             text = json.contents;
          } else {
             text = await response.text();
          }

          if (!text) throw new Error(`Empty response from ${proxyBase}`);
          return text;
        } catch (e) {
          console.warn(`Proxy ${proxyBase} failed:`, e);
          lastError = e;
        }
      }
      throw lastError || new Error("All proxies failed");
    };

    const checkBing = async () => {
      let status: Status = 'unknown';
      let debugMsg = '';

      try {
        setBingStatus('loading');

        // 1. Try Scraping First
        try {
            const targetUrl = 'https://www.isitdownrightnow.com/maps.bing.com.html';
            const htmlText = await fetchWithFallback(targetUrl, [
                'https://api.allorigins.win/get?url=', // Use AllOrigins JSON mode for better text extraction
                'https://corsproxy.io/'
            ]);

            const lowerHtml = htmlText.toLowerCase();
            debugMsg = htmlText.substring(0, 300);

            if (lowerHtml.includes('class="status_up"') || lowerHtml.includes("class='status_up'")) {
                 status = 'healthy';
            } else if (lowerHtml.includes('class="status_down"') || lowerHtml.includes("class='status_down'")) {
                 status = 'critical';
            } else if (lowerHtml.includes('is down for everyone')) {
                status = 'critical';
            } else if (lowerHtml.includes('is up and reachable') || lowerHtml.includes('reachable by us')) {
                status = 'healthy';
            }
        } catch (scrapeError: any) {
            debugMsg = `Scrape failed: ${scrapeError.message}`;
        }

        // 2. Fallback: Direct Connection Test if scrape failed or was inconclusive
        if (status === 'unknown') {
            debugMsg += " | Attempting Direct Ping...";
            // Try to load a generic map tile from Bing Maps CDN
            const isReachable = await testDirectConnection('https://ecn.t0.tiles.virtualearth.net/tiles/r0.jpeg?g=1&mkt=en-US');

            if (isReachable) {
                status = 'healthy';
                debugMsg += " | Direct Ping: SUCCESS";
            } else {
                status = 'unreachable';
                debugMsg += " | Direct Ping: FAILED";
            }
        }

        setBingStatus(status);
        setBingDebug(debugMsg);

      } catch (error: any) {
        console.error('Bing Check Error:', error);
        setBingStatus('unreachable');
        setBingDebug(`Critical Failure: ${error.message}`);
      }
    };

    const checkGoogle = async () => {
      let status: Status = 'unknown';
      let debugMsg = '';

      try {
        setGoogleStatus('loading');

        // 1. Try Scraping First
        try {
            const targetUrl = 'https://downdetector.com/status/google-maps/';
            const htmlText = await fetchWithFallback(targetUrl, [
                 'https://corsproxy.io/'
            ]);

            const lowerHtml = htmlText.toLowerCase();
            debugMsg = htmlText.substring(0, 300);

            if (lowerHtml.includes('user reports indicate no current problems')) {
                status = 'healthy';
            } else if (lowerHtml.includes('user reports indicate possible problems')) {
                status = 'warning';
            } else if (lowerHtml.includes('user reports indicate problems')) {
                status = 'critical';
            }
        } catch (scrapeError: any) {
            debugMsg = `Scrape failed: ${scrapeError.message}`;
        }

        // 2. Fallback: Direct Connection Test
        if (status === 'unknown') {
             debugMsg += " | Attempting Direct Ping...";
             // Try to load a generic map tile from Google Maps
             const isReachable = await testDirectConnection('https://mt0.google.com/vt/lyrs=m&hl=en&x=0&y=0&z=0');

             if (isReachable) {
                 status = 'healthy';
                 debugMsg += " | Direct Ping: SUCCESS";
             } else {
                 status = 'unreachable';
                 debugMsg += " | Direct Ping: FAILED";
             }
        }

        setGoogleStatus(status);
        setGoogleDebug(debugMsg);

      } catch (error: any) {
        console.error('Google Check Error:', error);
        setGoogleStatus('unreachable');
        setGoogleDebug(`Critical Failure: ${error.message}`);
      }
    };

    checkBing();
    checkGoogle();
  }, []);

  const getStatusConfig = (status: Status) => {
    switch (status) {
      case 'healthy':
        return { color: 'bg-green-600 hover:bg-green-700', text: 'Healthy' };
      case 'warning':
        return { color: 'bg-yellow-500 hover:bg-yellow-600', text: 'Warning' };
      case 'critical':
        return { color: 'bg-red-600 hover:bg-red-700', text: 'Critical' };
      case 'unreachable':
        return { color: 'bg-red-600 hover:bg-red-700', text: 'Unreachable' }; // Using Red for Unreachable
      case 'loading':
        return { color: 'bg-slate-700 hover:bg-slate-800', text: 'Checking...' };
      case 'unknown':
      default:
        return { color: 'bg-slate-600 hover:bg-slate-700', text: 'Unknown' };
    }
  };

  const bingConfig = getStatusConfig(bingStatus);
  const googleConfig = getStatusConfig(googleStatus);

  return (
    <div className="flex flex-col min-h-screen p-4">
      <header className="flex items-center mb-6">
        <button onClick={onBack} className="p-2 -ml-2">
          <BackArrowIcon />
        </button>
        <h1 className="text-xl font-bold ml-2">RADAR & Member Validation</h1>
      </header>
      <main className="flex-grow flex flex-col gap-6">
        {/* Bing Maps Button */}
        <button
          onClick={() => window.open('https://www.isitdownrightnow.com/maps.bing.com.html', '_blank', 'noopener,noreferrer')}
          className={`flex-1 w-full rounded-2xl shadow-xl flex flex-col items-center justify-center p-8 transition-all transform hover:scale-[1.02] ${bingConfig.color}`}
        >
          <div className="bg-white/20 p-4 rounded-full mb-4">
             <MapLocationIcon className="h-16 w-16 text-white" />
          </div>
          <h2 className="text-3xl font-bold text-white mb-2">BING Maps</h2>
          <span className="text-2xl font-semibold text-white uppercase tracking-wider">
            {bingConfig.text}
          </span>
          <span className="text-sm font-medium text-white/80 mt-1">Press to go Details</span>

          {(bingStatus === 'unknown') && (
              <div className="mt-4 p-2 bg-black/30 rounded text-xs text-left w-full overflow-hidden font-mono h-24 overflow-y-auto break-all">
                <strong>Debug Info:</strong><br/>
                {bingDebug}
              </div>
          )}
        </button>

        {/* Google Maps Button */}
        <button
          onClick={() => window.open('https://downdetector.com/status/google-maps/', '_blank', 'noopener,noreferrer')}
          className={`flex-1 w-full rounded-2xl shadow-xl flex flex-col items-center justify-center p-8 transition-all transform hover:scale-[1.02] ${googleConfig.color}`}
        >
          <div className="bg-white/20 p-4 rounded-full mb-4">
             <MapLocationIcon className="h-16 w-16 text-white" />
          </div>
          <h2 className="text-3xl font-bold text-white mb-2">Google Maps</h2>
          <span className="text-2xl font-semibold text-white uppercase tracking-wider">
            {googleConfig.text}
          </span>
          <span className="text-sm font-medium text-white/80 mt-1">Press to go Details</span>

          {(googleStatus === 'unknown') && (
              <div className="mt-4 p-2 bg-black/30 rounded text-xs text-left w-full overflow-hidden font-mono h-24 overflow-y-auto break-all">
                <strong>Debug Info:</strong><br/>
                {googleDebug}
              </div>
          )}
        </button>
      </main>
    </div>
  );
};

export default RadarStatusPage;

/**
 * Cloudflare Status Scraper Page
 *
 * Fetches the official Cloudflare Status page (HTML) via a CORS proxy and extracts status info.
 * 
 * Technical Implementation:
 * - Fetches raw HTML string via proxy (CorsProxy.io or AllOrigins).
 * - Uses the browser's DOMParser to convert the string into a DOM structure.
 * - Queries the DOM for specific class names used by the status page provider to find the 'North America' region component.
 * - Maps the status text (e.g., 'Operational', 'Degraded') to UI colors.
 */

import React, { useEffect, useState } from 'react';
import { BackArrowIcon, CloudflareIcon } from './icons';

interface CloudflareStatusPageProps {
  onBack: () => void;
}

interface LocationStatus {
  name: string;
  status: string;
}

const CloudflareStatusPage: React.FC<CloudflareStatusPageProps> = ({ onBack }) => {
  const [locations, setLocations] = useState<LocationStatus[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [lastUpdated, setLastUpdated] = useState<string>('');

  useEffect(() => {
    const fetchStatus = async () => {
      try {
        const targetUrl = 'https://www.cloudflarestatus.com/';
        // Use corsproxy.io as primary, allorigins as backup
        const proxies = [
          'https://corsproxy.io/?' + encodeURIComponent(targetUrl),
          'https://api.allorigins.win/get?url=' + encodeURIComponent(targetUrl)
        ];

        let htmlText = '';
        let success = false;

        for (const proxyUrl of proxies) {
          try {
            const response = await fetch(proxyUrl);
            if (!response.ok) continue;

            if (proxyUrl.includes('allorigins')) {
               const data = await response.json();
               htmlText = data.contents;
            } else {
               htmlText = await response.text();
            }

            if (htmlText) {
              success = true;
              break;
            }
          } catch (e) {
            console.warn("Proxy failed", e);
          }
        }

        if (!success || !htmlText) {
          throw new Error("Unable to fetch status data. Please try again later.");
        }

        // Parse HTML
        const parser = new DOMParser();
        const doc = parser.parseFromString(htmlText, 'text/html');

        // Find the "North America" component container
        // Structure is usually: .component-container > .component-inner-container > .name (text=North America)
        const nameElements = Array.from(doc.querySelectorAll('.name'));
        const naHeader = nameElements.find(el => el.textContent?.trim() === 'North America');

        if (!naHeader) {
          throw new Error("North America section not found in status page.");
        }

        // Navigate up to the component container
        // .component-inner-container -> .component-container
        const container = naHeader.closest('.component-container');
        if (!container) {
          throw new Error("Could not identify status container.");
        }

        // Find children components
        const childContainer = container.querySelector('.child-components-container');
        if (!childContainer) {
           throw new Error("No locations found under North America.");
        }

        const componentRows = Array.from(childContainer.querySelectorAll('.component-inner-container'));

        const extracted: LocationStatus[] = componentRows.map(row => {
          const nameEl = row.querySelector('.name');
          const statusEl = row.querySelector('.component-status');
          return {
            name: nameEl?.textContent?.trim() || 'Unknown Location',
            status: statusEl?.textContent?.trim() || 'Unknown'
          };
        }).filter(item => item.name !== 'Unknown Location');

        setLocations(extracted);
        setLastUpdated(new Date().toLocaleTimeString());

      } catch (err: any) {
        console.error(err);
        setError(err.message || 'An unexpected error occurred.');
      } finally {
        setLoading(false);
      }
    };

    fetchStatus();
  }, []);

  const getStatusColor = (status: string) => {
    const s = status.toLowerCase();
    if (s === 'operational') return 'text-green-400';
    if (s.includes('maintenance')) return 'text-blue-400';
    if (s.includes('degraded')) return 'text-yellow-400';
    if (s.includes('outage')) return 'text-red-500';
    return 'text-slate-400';
  };

  const getStatusDot = (status: string) => {
    const s = status.toLowerCase();
    if (s === 'operational') return 'bg-green-500';
    if (s.includes('maintenance')) return 'bg-blue-500';
    if (s.includes('degraded')) return 'bg-yellow-500';
    if (s.includes('outage')) return 'bg-red-500';
    return 'bg-slate-500';
  };

  return (
    <div className="flex flex-col min-h-screen p-4">
      <header className="flex items-center mb-6 sticky top-0 bg-slate-900 z-10 py-2">
        <button onClick={onBack} className="p-2 -ml-2 hover:bg-slate-800 rounded-full transition-colors">
          <BackArrowIcon />
        </button>
        <div className="ml-2">
          <h1 className="text-xl font-bold flex items-center gap-2">
            <CloudflareIcon />
            Cloudflare Status
          </h1>
          <p className="text-xs text-slate-400">North America Region</p>
        </div>
      </header>

      <main className="flex-grow">
        {loading && (
          <div className="flex flex-col items-center justify-center h-64 space-y-4">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-white"></div>
            <p className="text-slate-400 animate-pulse">Fetching latest status...</p>
          </div>
        )}

        {error && (
          <div className="bg-red-900/50 border border-red-500 p-6 rounded-lg text-center">
            <p className="text-white font-semibold mb-2">Error Loading Status</p>
            <p className="text-red-200 text-sm">{error}</p>
            <button 
              onClick={() => window.location.reload()} 
              className="mt-4 bg-red-700 hover:bg-red-600 text-white px-4 py-2 rounded text-sm transition-colors"
            >
              Retry
            </button>
          </div>
        )}

        {!loading && !error && locations.length > 0 && (
          <div className="space-y-4">
            <div className="text-right text-xs text-slate-500 mb-2">
              Last updated: {lastUpdated}
            </div>
            <div className="grid gap-3">
              {locations.map((loc, idx) => (
                <div key={idx} className="bg-slate-800 p-4 rounded-lg flex items-center justify-between shadow-sm hover:bg-slate-750 transition-colors">
                  <span className="font-medium text-slate-200">{loc.name}</span>
                  <div className="flex items-center gap-2">
                    <span className={`text-sm font-semibold ${getStatusColor(loc.status)}`}>
                      {loc.status}
                    </span>
                    <span className={`h-3 w-3 rounded-full ${getStatusDot(loc.status)}`}></span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {!loading && !error && locations.length === 0 && (
          <div className="text-center p-8 text-slate-400">
            No locations found for North America.
          </div>
        )}
      </main>
    </div>
  );
};

export default CloudflareStatusPage;

/**
 * Share App Page
 *
 * Allows users to share the application link with colleagues via native mobile intents.
 * - 'mailto:' for Email sharing
 * - 'sms:' for Text Message sharing
 */

import React from 'react';
import { BackArrowIcon, MailIcon, MessageIcon } from './icons';

interface SharePageProps {
  onBack: () => void;
}

const SharePage: React.FC<SharePageProps> = ({ onBack }) => {
  // Define the content in one place to ensure consistency between Email and SMS
  const shareSubject = "New ACE EdgeWatch App";
  const shareBodyContent = `Try this during your next Sev 1 or Sev 2 call, This app shows in seconds whether a problem is with providers like Microsoft or AWS, so you stop guessing and start fixing faster.
No install needed – it runs right in your browser from a simple link.
https://ace-edge-watch-git-main-ace-edgewatchs-projects.vercel.app`;

  const handleEmailShare = () => {
    const subject = encodeURIComponent(shareSubject);
    const body = encodeURIComponent(shareBodyContent);
    window.location.href = `mailto:?subject=${subject}&body=${body}`;
  };

  const handleSmsShare = () => {
    // For SMS, we combine the Subject and Body into a single message since SMS doesn't have a 'Subject' field
    const fullMessage = `${shareSubject}\n\n${shareBodyContent}`;
    const encodedBody = encodeURIComponent(fullMessage);

    // Using 'sms:?body=' is the standard way to open the default SMS app
    // leaving the number empty prompts the user to select a contact
    window.location.href = `sms:?body=${encodedBody}`;
  };

  return (
    <div className="flex flex-col min-h-screen p-4 text-white relative">
        <style>{`
            .glass-panel {
                background: rgba(30, 41, 59, 0.7);
                backdrop-filter: blur(10px);
                border: 1px solid rgba(255, 255, 255, 0.1);
                box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
            }
        `}</style>

        {/* Background Gradients (matching HomePage) */}
        <div className="fixed inset-0 pointer-events-none -z-10">
            <div className="absolute top-[10%] -right-[10%] w-[50%] h-[50%] rounded-full bg-pink-900/20 blur-[100px]" />
            <div className="absolute -bottom-[20%] left-[10%] w-[60%] h-[60%] rounded-full bg-purple-900/20 blur-[100px]" />
        </div>

      <header className="flex items-center mb-8">
        <button onClick={onBack} className="p-2 -ml-2 hover:bg-white/10 rounded-full transition-colors">
          <BackArrowIcon />
        </button>
        <h1 className="text-xl font-bold ml-2 tracking-wide">Share ACE EdgeWatch</h1>
      </header>

      <main className="flex-grow flex flex-col gap-4">

        {/* Email Share Button */}
        <button
            onClick={handleEmailShare}
            className="group relative w-full flex items-center gap-4 p-5 rounded-xl bg-slate-800 border border-slate-600 hover:border-pink-400 transition-all duration-300 hover:bg-slate-700 hover:shadow-lg hover:shadow-pink-500/20 active:scale-[0.98]"
        >
            <div className="p-3 rounded-lg bg-pink-500/10 text-pink-400 group-hover:bg-pink-500/20 group-hover:text-pink-300 transition-colors">
                <MailIcon />
            </div>
            <div className="flex-1 text-left">
                <h3 className="font-semibold text-slate-100 text-lg">Share by E-mail</h3>
                <p className="text-xs text-slate-400 group-hover:text-slate-300">Send a link via your mail app</p>
            </div>
            <div className="text-slate-500 group-hover:text-pink-300">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M7.293 14.707a1 1 0 010-1.414L10.586 10 7.293 6.707a1 1 0 011.414-1.414l4 4a1 1 0 010 1.414l-4 4a1 1 0 01-1.414 0z" clipRule="evenodd" />
                </svg>
            </div>
        </button>

        {/* SMS Share Button */}
        <button
            onClick={handleSmsShare}
            className="group relative w-full flex items-center gap-4 p-5 rounded-xl bg-slate-800 border border-slate-600 hover:border-green-400 transition-all duration-300 hover:bg-slate-700 hover:shadow-lg hover:shadow-green-500/20 active:scale-[0.98]"
        >
            <div className="p-3 rounded-lg bg-green-500/10 text-green-400 group-hover:bg-green-500/20 group-hover:text-green-300 transition-colors">
                <MessageIcon />
            </div>
            <div className="flex-1 text-left">
                <h3 className="font-semibold text-slate-100 text-lg">Share by SMS/TEXT</h3>
                <p className="text-xs text-slate-400 group-hover:text-slate-300">Send a link via text message</p>
