/**
 * Application Status Page
 *
 * Displays a grid of enterprise applications (E-Commerce, Tableau, Salesforce products, etc.).
 * Each tile links to either an external status page (e.g., DownDetector) or an internal status view.
 *
 * Includes specific handling for products like Salesforce that require regional checks.
 * 
 */

import React, { useState } from 'react';
import type { Page } from '../App';
import { BackArrowIcon, CartIcon, MailIcon, PhoneIcon, KeyIcon, PlaceholderIcon, CloudIcon, MultipleAppsIcon, FamilyIcon, TableauIcon, MuleSoftIcon, CarIcon, OldPhoneIcon, GuidewireIcon } from './icons';

interface ApplicationPageProps {
  onNavigate: (page: Page) => void;
}

interface TileProps {
  icon: React.ReactNode;
  title: string;
  subtitle?: string;
  onClick?: () => void;
  disabled?: boolean;
}

const ServiceTile: React.FC<TileProps> = ({ icon, title, subtitle, onClick, disabled = false }) => {
  const baseClasses = "bg-slate-800 rounded-lg p-4 flex flex-col items-center justify-center aspect-square text-center space-y-2 transition-all duration-200";
  const interactiveClasses = "hover:bg-slate-700 hover:scale-105 transform cursor-pointer";
  const disabledClasses = "opacity-50 cursor-not-allowed";

  return (
    <button
      onClick={onClick}
      disabled={disabled}
      className={`${baseClasses} ${disabled ? disabledClasses : interactiveClasses}`}
    >
      {icon}
      <div className="flex flex-col items-center leading-tight">
        <span className="font-semibold text-sm">{title}</span>
        {subtitle && <span className="text-xs text-slate-400 mt-1 font-normal">{subtitle}</span>}
      </div>
    </button>
  );
};

// Simple Modal Component
const MessageBox: React.FC<{ isOpen: boolean; message: string; onConfirm: () => void }> = ({ isOpen, message, onConfirm }) => {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-4">
      <div className="bg-slate-800 border border-slate-600 rounded-lg shadow-2xl max-w-sm w-full p-6 text-center">
        <p className="text-white text-lg mb-6 leading-relaxed">{message}</p>
        <button
          onClick={onConfirm}
          className="bg-cyan-500 hover:bg-cyan-600 text-white font-semibold py-2 px-8 rounded transition-colors"
        >
          OK
        </button>
      </div>
    </div>
  );
};

const ApplicationPage: React.FC<ApplicationPageProps> = ({ onNavigate }) => {
  const [popupState, setPopupState] = useState<{ isOpen: boolean; message: string; onConfirm: () => void }>({
    isOpen: false,
    message: '',
    onConfirm: () => {},
  });

  const closePopup = () => {
    setPopupState((prev) => ({ ...prev, isOpen: false }));
  };

  const handleRadarClick = () => {
    setPopupState({
      isOpen: true,
      message: "RADAR and Member Validation may run slowly if Bing Maps is affected. Tap OK to test Bing and Google Maps health.",
      onConfirm: () => {
        closePopup();
        onNavigate('radar-status');
      }
    });
  };

  const handleSalesforceProductClick = (productName: string, url: string) => {
    setPopupState({
      isOpen: true,
      message: `The ${productName} status page does not support direct region linking. Please check the 'Americas' box manually on the next screen to filter results.`,
      onConfirm: () => {
        closePopup();
        window.open(url, '_blank', 'noopener,noreferrer');
      }
    });
  };

  return (
    <div className="flex flex-col min-h-screen p-4 relative">
      <MessageBox 
        isOpen={popupState.isOpen} 
        message={popupState.message} 
        onConfirm={popupState.onConfirm} 
      />

      <header className="flex items-center mb-6">
        <button onClick={() => onNavigate('home')} className="p-2 -ml-2">
          <BackArrowIcon />
        </button>
        <h1 className="text-xl font-bold ml-2">ACE App Cloud Service Status</h1>
      </header>
      <main className="grid grid-cols-2 gap-4">
        {/* Guidewire button added */}
        <ServiceTile 
            icon={<GuidewireIcon className="h-10 w-10" />} 
            title="Guidewire" 
            subtitle="Health Check"
            onClick={() => onNavigate('guidewire')} 
        />
        <ServiceTile 
            icon={<OldPhoneIcon className="h-8 w-8 text-cyan-400" />} 
            title="GENESYS" 
            subtitle="Health Check"
            onClick={() => onNavigate('genesys')} 
        />
        <ServiceTile 
            icon={<CartIcon />} 
            title="E-Commerce" 
            subtitle="AWS"
            onClick={() => window.open('https://downdetector.com/status/aws-amazon-web-services/', '_blank', 'noopener,noreferrer')} 
        />

        {/* Next Row */}
        <ServiceTile 
          icon={<FamilyIcon />} 
          title="RADAR & Member Validation" 
          subtitle="Bing & Google Maps"
          onClick={handleRadarClick} 
        />
        <ServiceTile 
            icon={<TableauIcon />} 
            title="Tableau" 
            onClick={() => handleSalesforceProductClick('Tableau', 'https://status.salesforce.com/products/Tableau')} 
        />

        {/* Next Row */}
        <ServiceTile 
            icon={<MuleSoftIcon />} 
            title="MuleSoft" 
            onClick={() => handleSalesforceProductClick('MuleSoft', 'https://status.salesforce.com/products/Mulesoft')} 
        />
        <ServiceTile 
          icon={<KeyIcon />} 
          title="SSO" 
          subtitle="per Azure Downdetector" 
          onClick={() => window.open('https://downdetector.com/status/windows-azure/', '_blank', 'noopener,noreferrer')} 
        />

        {/* Next Row */}
        <ServiceTile 
          icon={<CloudIcon />} 
          title="Azure Health" 
          subtitle="per Microsoft" 
          onClick={() => window.open('https://portal.azure.com/#view/Microsoft_Azure_Health/AzureHealthBrowseBlade/~/serviceIssues', '_blank', 'noopener,noreferrer')} 
        />
        <ServiceTile icon={<PhoneIcon />} title="Intune" onClick={() => window.open('https://statusgator.com/services/microsoft-intune', '_blank', 'noopener,noreferrer')} />

        {/* Next Row */}
        <ServiceTile icon={<MailIcon />} title="Outlook" onClick={() => window.open('https://downdetector.com/status/outlook/', '_blank', 'noopener,noreferrer')} />
        <ServiceTile 
          icon={<MultipleAppsIcon />} 
          title="Claims Pay, TLO, N2uitive & ISO" 
          subtitle="Cloudflare"
          onClick={() => onNavigate('cloudflare-status')} 
        />

        {/* Next Row */}
        <ServiceTile 
            icon={<CarIcon />} 
            title="CA DMV" 
            subtitle="DownDetector"
            onClick={() => window.open('https://downdetector.com/status/california-dmv/', '_blank', 'noopener,noreferrer')} 
        />
      </main>
    </div>
  );
};

export default ApplicationPage;

